/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const N = nums.length;

    // 1. Precalculate closest(x) for all x
    const closest = new Array(N);
    for (let x = 0; x < N; x++) {
        if (x === 0) {
            closest[x] = 1;
        } else if (x === N - 1) {
            closest[x] = N - 2;
        } else {
            const diff_left = nums[x] - nums[x - 1];
            const diff_right = nums[x + 1] - nums[x];

            if (diff_left <= diff_right) {
                // Tie breaker chooses smaller index (x-1)
                closest[x] = x - 1;
            } else {
                closest[x] = x + 1;
            }
        }
    }

    // Min Priority Queue implementation for Dijkstra's
    // Stores [cost, index]
    class MinPriorityQueue {
        constructor() {
            this.heap = [];
        }

        isEmpty() {
            return this.heap.length === 0;
        }

        getParentIndex(i) { return Math.floor((i - 1) / 2); }
        getLeftChildIndex(i) { return 2 * i + 1; }
        getRightChildIndex(i) { return 2 * i + 2; }

        swap(i, j) {
            [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
        }

        bubbleUp(index) {
            while (index > 0) {
                const parentIndex = this.getParentIndex(index);
                if (this.heap[index][0] < this.heap[parentIndex][0]) {
                    this.swap(index, parentIndex);
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }

        bubbleDown(index) {
            let minIndex = index;
            const size = this.heap.length;

            while (true) {
                const left = this.getLeftChildIndex(index);
                const right = this.getRightChildIndex(index);

                if (left < size && this.heap[left][0] < this.heap[minIndex][0]) {
                    minIndex = left;
                }
                if (right < size && this.heap[right][0] < this.heap[minIndex][0]) {
                    minIndex = right;
                }

                if (minIndex !== index) {
                    this.swap(index, minIndex);
                    index = minIndex;
                } else {
                    break;
                }
            }
        }

        enqueue(element) {
            this.heap.push(element);
            this.bubbleUp(this.heap.length - 1);
        }

        dequeue() {
            if (this.isEmpty()) return null;
            if (this.heap.length === 1) return this.heap.pop();

            const min = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.bubbleDown(0);
            return min;
        }
    }

    const results = [];

    for (const [start, end] of queries) {
        // Dijkstra's Algorithm
        const dist = new Array(N).fill(Infinity);
        const pq = new MinPriorityQueue();

        dist[start] = 0;
        pq.enqueue([0, start]);

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > dist[u]) {
                continue;
            }

            if (u === end) {
                // Optimization: we found the shortest path to the target
                break;
            }

            // --- Move Type 2: To closest(u), Cost = 1 ---
            const v_closest = closest[u];
            const cost_2 = 1;
            if (dist[u] + cost_2 < dist[v_closest]) {
                dist[v_closest] = dist[u] + cost_2;
                pq.enqueue([dist[v_closest], v_closest]);
            }

            // --- Move Type 1: To any other index v, Cost = |nums[u] - nums[v]| ---
            // WARNING: This loop leads to O(N^2) complexity per query, which is necessary 
            // based on the problem statement's definition of Type 1 move, 
            // but might time out for N=10^5.
            for (let v = 0; v < N; v++) {
                if (u === v) continue;

                const cost_1 = Math.abs(nums[u] - nums[v]);

                if (dist[u] + cost_1 < dist[v]) {
                    dist[v] = dist[u] + cost_1;
                    pq.enqueue([dist[v], v]);
                }
            }
        }

        results.push(dist[end]);
    }

    return results;
}

