import java.util.Arrays;
import java.util.PriorityQueue;
import java.util.Comparator;

public class Solution {

    // Helper class for Dijkstra's Priority Queue elements: [cost, index]
    static class Node {
        long cost;
        int index;

        public Node(long cost, int index) {
            this.cost = cost;
            this.index = index;
        }
    }

    public static long[] solve(long[] nums, long[][] queries) {
        int N = nums.length;

        // 1. Precalculate closest(x) for all x
        int[] closest = new int[N];
        for (int x = 0; x < N; x++) {
            if (x == 0) {
                closest[x] = 1;
            } else if (x == N - 1) {
                closest[x] = N - 2;
            } else {
                // nums[x] - nums[x-1]
                long diffLeft = nums[x] - nums[x - 1];
                // nums[x+1] - nums[x]
                long diffRight = nums[x + 1] - nums[x];

                if (diffLeft <= diffRight) {
                    // Tie breaker chooses smaller index (x-1)
                    closest[x] = x - 1;
                } else {
                    closest[x] = x + 1;
                }
            }
        }

        long[] results = new long[queries.length];

        for (int i = 0; i < queries.length; i++) {
            // Since queries[i] = [l_i, r_i], we cast the long indices to int for array access
            int start = (int) queries[i][0];
            int end = (int) queries[i][1];

            // Dijkstra's Algorithm
            long[] dist = new long[N];
            Arrays.fill(dist, Long.MAX_VALUE);

            // Min Priority Queue storing Node(cost, index)
            PriorityQueue<Node> pq = new PriorityQueue<>(Comparator.comparingLong(n -> n.cost));

            dist[start] = 0;
            pq.add(new Node(0, start));

            while (!pq.isEmpty()) {
                Node current = pq.poll();
                long d = current.cost;
                int u = current.index;

                if (d > dist[u]) {
                    continue;
                }

                if (u == end) {
                    // Optimization: we found the shortest path to the target
                    break;
                }

                // --- Move Type 2: To closest(u), Cost = 1 ---
                int vClosest = closest[u];
                long cost2 = 1;
                if (dist[u] + cost2 < dist[vClosest]) {
                    dist[vClosest] = dist[u] + cost2;
                    pq.add(new Node(dist[vClosest], vClosest));
                }

                // --- Move Type 1: To any other index v, Cost = |nums[u] - nums[v]| ---
                // O(N) loop for Type 1 edges
                for (int v = 0; v < N; v++) {
                    if (u == v) continue;

                    // Cost = |nums[u] - nums[v]|
                    long cost1 = Math.abs(nums[u] - nums[v]);

                    if (dist[u] + cost1 < dist[v]) {
                        dist[v] = dist[u] + cost1;
                        pq.add(new Node(dist[v], v));
                    }
                }
            }
            results[i] = dist[end];
        }

        return results;
    }
}

